import re
from os import path
import json as js

def main():
    modules = set()
    for line in sys.argv[1].split('\n'):
        if 'import' in line or 'from' in line:
            match_import = re.match(r'(?:from (\w+) import|import)(\s*\w+)(?:\.\w+|)', line)
            if match_import:
                modules.add(match_import.group(2))
    for module in sorted(list(modules)):
        print(module)

